    TResult? Function(GenreToggled value)? genreToggled,
    TResult? Function(SubmitRequested value)? submitRequested,
  }) {
    return submitRequested?.call(this);
  }

  @override
  @optionalTypeArgs
  TResult maybeMap<TResult extends Object?>({
    TResult Function(Started value)? started,
    TResult Function(GuaranteeChanged value)? guaranteeChanged,
    TResult Function(SplitToggled value)? splitToggled,
    TResult Function(GenreToggled value)? genreToggled,
    TResult Function(SubmitRequested value)? submitRequested,
    required TResult orElse(),
  }) {
    if (submitRequested != null) {
      return submitRequested(this);
    }
    return orElse();
  }
}

abstract class SubmitRequested implements CreateSlotEvent {
  const factory SubmitRequested() = _$SubmitRequestedImpl;
}
